-- migrate:up
-- Bootstrapping seed: the scrapeable thinker roster + their source manifest.
-- Thinkers are inserted FIRST (by name) so the image/bio updates and the
-- scrape_sources rows below resolve on a brand-new database — no ETL needed.
-- Everything else (claims, predictions, the trend map) is produced by the pipeline.

-- 1. Thinker roster (name only; the pipeline + evaluate fill scores over time).

-- 2. Portraits + bios (match thinkers by slug, exactly as the frontend slugifies).
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/c/c0/Andrej_Karpathy%2C_OpenAI.png', bio = COALESCE(NULLIF(bio, ''), 'Andrej Karpathy is a deep learning researcher and former VP of AI at Tesla and research scientist at OpenAI. He created influential educational resources including micrograd and nanoGPT, and is widely credited with popularising the concept of ''vibe coding''. A key figure in making neural networks legible to engineers and builders outside academia.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'andrej-karpathy';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8a/Andrew_McAfee_FT-McKinsey_BBYA_2014%28LowerContrast%29.jpg/500px-Andrew_McAfee_FT-McKinsey_BBYA_2014%28LowerContrast%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Andrew McAfee is a principal research scientist at MIT and co-director of the MIT Initiative on the Digital Economy. Co-author of ''The Second Machine Age'' and ''More from Less'', he is one of the most cited voices on how digital technology reshapes labour markets, productivity, and environmental footprint.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'andrew-mcafee';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/ASSA_2026_-_Anton_Korinek_02_%28cropped%29.jpg/500px-ASSA_2026_-_Anton_Korinek_02_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Anton Korinek is an economist at the University of Virginia and a fellow at the Brookings Institution, specialising in the macroeconomic implications of AI. His research examines how advanced AI affects labour markets, inequality, and economic growth — with an unusual willingness to model extreme AI scenarios rigorously.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'anton-korinek';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6c/Azeem_Azhar_%28born_1972%29.png/500px-Azeem_Azhar_%28born_1972%29.png', bio = COALESCE(NULLIF(bio, ''), 'Azeem Azhar is a British entrepreneur, analyst, and author of ''The Exponential Age''. Founder of Exponential View, one of the most-read technology newsletters in policy and business circles. He argues that exponential technology growth creates structural gaps between capability and society''s capacity to adapt.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'azeem-azhar';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/49/Ben_Thompson_-_Innholdprodusentens_d%C3%B8d_og_mulige_gjenoppstandelse_-_NMD_2016_%2826890581672%29_%28cropped%29.jpg/500px-Ben_Thompson_-_Innholdprodusentens_d%C3%B8d_og_mulige_gjenoppstandelse_-_NMD_2016_%2826890581672%29_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Ben Thompson is the founder of Stratechery, the definitive independent analysis publication on technology strategy and business models. A former Microsoft and Apple employee, his frameworks — including ''aggregation theory'' — have shaped how practitioners understand platform competition and AI''s structural impact on media and enterprise.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'ben-thompson';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/75/BENJAMIN_BRATTON_IN_2025_by_Christopher_michel_02.jpg/500px-BENJAMIN_BRATTON_IN_2025_by_Christopher_michel_02.jpg', bio = COALESCE(NULLIF(bio, ''), 'Benjamin Bratton is a design theorist, sociologist, and professor at UC San Diego. Author of ''The Stack: On Software and Sovereignty'' and ''The Revenge of the Real'', he develops large-scale conceptual frameworks for understanding planetary computation, AI governance, and post-pandemic biopolitics.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'benjamin-bratton';
UPDATE thinkers SET image_url = 'https://substack-post-media.s3.amazonaws.com/public/images/95c72d65-684b-4a0d-b225-9b9e1da2f4c4_606x747.jpeg', bio = COALESCE(NULLIF(bio, ''), 'Craig Hepburn is a senior AI strategist and practitioner writing at the intersection of enterprise AI adoption, agentic systems, and organisational change. His work focuses on the practical realities of deploying AI inside large organisations — cutting through hype to surface what actually transforms teams and decision-making.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'craig-hepburn';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e4/Dario_Amodei_at_TechCrunch_Disrupt_2023_01_%28cropped%29.jpg/500px-Dario_Amodei_at_TechCrunch_Disrupt_2023_01_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Dario Amodei is co-founder and CEO of Anthropic, which he founded with his sister Daniela after leaving OpenAI. A physicist by training, he leads one of the most safety-focused frontier AI labs. His essay ''Machines of Loving Grace'' laid out a detailed optimistic vision of AI transforming medicine, mental health, and economic development within years.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'dario-amodei';
UPDATE thinkers SET image_url = 'https://www.speakersassociates.com/wp-content/uploads/2025/06/David-Mattin-Speaker.jpg', bio = COALESCE(NULLIF(bio, ''), 'David Mattin is the founder of New World Same Humans, a newsletter exploring how technology reshapes human identity, culture, and society. A former head of trends and insights at TrendWatching, he brings a humanistic lens to questions about AI consciousness, meaning, and the long-arc transformation of how people understand themselves.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'david-mattin';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2b/Demis_Hassabis%2C_2024_Nobel_Prize_Laureate_in_Chemistry_7_%28cropped%29.jpg/500px-Demis_Hassabis%2C_2024_Nobel_Prize_Laureate_in_Chemistry_7_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Demis Hassabis is co-founder and CEO of Google DeepMind. A chess prodigy, neuroscientist, and game developer, he built DeepMind into the lab behind AlphaGo, AlphaFold, and Gemini. He was awarded the 2024 Nobel Prize in Chemistry for protein structure prediction. His conviction is that AI is the most transformative technology in human history.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'demis-hassabis';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9a/Elad_Gil_%2853006122469%29.jpg/500px-Elad_Gil_%2853006122469%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Elad Gil is a serial entrepreneur, investor, and author of ''High Growth Handbook''. An early engineer at Google and Twitter, he has backed some of the most influential AI companies including Anthropic, Stripe, and Airbnb. He writes widely on how to build and scale companies in periods of rapid technological transition.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'elad-gil';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Mostaque.jpg/500px-Mostaque.jpg', bio = COALESCE(NULLIF(bio, ''), 'Emad Mostaque is the founder of Stability AI, the company behind Stable Diffusion, one of the world''s most widely used open-source image generation models. A former hedge fund analyst, he became a central figure in the debate over open vs. closed AI development, and has argued that AI should be decentralised and sovereign.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'emad-mostaque';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/55/Erik_Brynjolfsson_at_MIT_Sloan_CIO_Symposium_2013_%28cropped%29.jpg/500px-Erik_Brynjolfsson_at_MIT_Sloan_CIO_Symposium_2013_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Erik Brynjolfsson is a professor at Stanford and a senior fellow at the Stanford Institute for Human-Centered AI. Co-author of ''The Second Machine Age'' and ''Machine Platform Crowd'', his research on the productivity paradox — why GDP statistics fail to capture digital-era value creation — has shaped economic thinking about AI''s impact on growth.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'erik-brynjolfsson';
UPDATE thinkers SET image_url = 'https://faculty.wharton.upenn.edu/wp-content/uploads/2016/11/ethan-happy-hour-headshot-philadelphia-2023-45934.jpg', bio = COALESCE(NULLIF(bio, ''), 'Ethan Mollick is an associate professor at the Wharton School of the University of Pennsylvania, where he studies entrepreneurship and innovation. Author of ''Co-Intelligence: Living and Working with AI'', he is one of the most widely read practitioners of applied AI experimentation — known for systematic, honest tests of what current AI can and cannot do in real work contexts.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'ethan-mollick';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c7/Fei-Fei_Li_at_AI_for_Good_2017.jpg/500px-Fei-Fei_Li_at_AI_for_Good_2017.jpg', bio = COALESCE(NULLIF(bio, ''), 'Fei-Fei Li is a professor at Stanford University and co-director of the Stanford Human-Centered AI Institute. Creator of ImageNet, the dataset that catalysed the deep learning revolution, she is one of the most important figures in modern AI. Her book ''The Worlds I See'' documents her journey from immigrant to defining voice on responsible, human-centred AI development.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'fei-fei-li';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/In_the_European_Night_Will_the_Union_Survive%3F_Franco_Berardi_%283x4_cropped%29.jpg/500px-In_the_European_Night_Will_the_Union_Survive%3F_Franco_Berardi_%283x4_cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Franco ''Bifo'' Berardi is an Italian Marxist philosopher, media theorist, and activist. A founding figure of the Italian autonomia movement, he writes on the psychopathology of digital labour, the collapse of the social sphere under financialisation, and the cognitive and emotional toll of networked capitalism — perspectives that offer a sharply critical counterpoint to techno-optimism.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'franco-bifo-berardi';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cf/Geoff_Mulgan.jpg/500px-Geoff_Mulgan.jpg', bio = COALESCE(NULLIF(bio, ''), 'Geoff Mulgan is a professor at UCL and former chief executive of Nesta, the UK''s innovation foundation. A former head of policy in Downing Street, he combines systems thinking with practical institution-building, writing on collective intelligence, public sector innovation, and how democratic societies should govern transformative AI.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'geoff-mulgan';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/30/Geoffrey_E._Hinton%2C_2024_Nobel_Prize_Laureate_in_Physics_%28cropped1%29.jpg/500px-Geoffrey_E._Hinton%2C_2024_Nobel_Prize_Laureate_in_Physics_%28cropped1%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Geoffrey Hinton is the ''godfather of deep learning'' — a cognitive psychologist and computer scientist whose decades of work on neural networks and backpropagation laid the foundations for modern AI. He was awarded the 2024 Nobel Prize in Physics. He resigned from Google in 2023 explicitly to speak more freely about AI existential risk, and has since become one of the most prominent voices warning that AI may become uncontrollable.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'geoffrey-hinton';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d0/Nordiske_Mediedager_%285713109710%29.jpg/500px-Nordiske_Mediedager_%285713109710%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Gerd Leonhard is a Switzerland-based futurist, author, and keynote speaker. His books ''Technology vs. Humanity'' and ''The Future of Business'' argue for human values as a guardrail against exponential technology. He is a vocal critic of hyper-digitalisation and an advocate for a European approach to AI governance that centres human dignity.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'gerd-leonhard';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/17/Jakob_Nielsen_1_%28cropped_again%29.jpg/500px-Jakob_Nielsen_1_%28cropped_again%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Jakob Nielsen is the co-founder of Nielsen Norman Group and the world''s foremost authority on usability and user experience design. His heuristics have shaped how digital products are built for three decades. In recent years he has become a prominent voice on AI and UX, arguing that conversational AI is the most significant shift in interface design since the graphical user interface.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'jakob-nielsen';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e6/Jen-Hsun_Huang_2025.jpg/500px-Jen-Hsun_Huang_2025.jpg', bio = COALESCE(NULLIF(bio, ''), 'Jensen Huang is the co-founder and CEO of NVIDIA, which under his leadership became the defining infrastructure company of the AI era. A semiconductor engineer with rare showmanship, his GPU architectures power virtually all frontier AI training. He has become one of the most influential commentators on the pace and trajectory of AI capability development.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'jensen-huang';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a6/Joscha_Bach_%2811524872763%29.jpg/500px-Joscha_Bach_%2811524872763%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Joscha Bach is a German AI researcher and cognitive scientist known for his work on artificial general intelligence, consciousness, and the computational basis of mind. A former fellow at MIT Media Lab and Harvard, he brings a deeply philosophical perspective to AI — exploring how models of cognition and mind-as-simulation apply to both artificial and biological intelligence.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'joscha-bach';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/01/Kevin_Kelly_in_2022_03.jpg/500px-Kevin_Kelly_in_2022_03.jpg', bio = COALESCE(NULLIF(bio, ''), 'Kevin Kelly is a co-founder of Wired magazine and one of the most prescient long-range technology thinkers of the past three decades. His books ''What Technology Wants'', ''The Inevitable'', and ''Excellent Advice for Living'' combine biology, anthropology, and systems thinking. He is consistently optimistic about AI as a tool for expanding human possibility.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'kevin-kelly';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Marc_Andreessen-9_%28cropped%29.jpg/500px-Marc_Andreessen-9_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Marc Andreessen is the co-creator of Mosaic (the first graphical web browser), co-founder of Netscape, and co-founder of Andreessen Horowitz, one of Silicon Valley''s most influential venture capital firms. His 2023 ''Techno-Optimist Manifesto'' is the defining document of accelerationist AI optimism, arguing that technology — including AI — is an unconditional good that should be scaled as fast as possible.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'marc-andreessen';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/34/Mariana_Mazzucato_2016_%28cropped%29.jpg/500px-Mariana_Mazzucato_2016_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Mariana Mazzucato is a professor in the Economics of Innovation and Public Value at UCL. Her books ''The Entrepreneurial State'' and ''Mission Economy'' challenge the narrative that innovation is driven by private risk-taking alone, arguing for an active, directional role for government in shaping AI''s development toward public missions rather than private accumulation.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'mariana-mazzucato';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Mustafa_Suleyman_photo_%28cropped%29.jpg/500px-Mustafa_Suleyman_photo_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Mustafa Suleyman is the CEO of Microsoft AI and co-founder of DeepMind. His book ''The Coming Wave'' is a defining account of how advanced AI and synthetic biology are becoming impossible to contain — and what that means for governments, companies, and democratic institutions. He occupies a unique position: simultaneously an AI accelerator and one of its most prominent internal critics.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'mustafa-suleyman';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3a/Prof_Nick_Bostrom_324-1.jpg/500px-Prof_Nick_Bostrom_324-1.jpg', bio = COALESCE(NULLIF(bio, ''), 'Nick Bostrom is a philosopher at the University of Oxford and founding director of the Future of Humanity Institute. His 2014 book ''Superintelligence'' was the foundational text for the modern AI safety movement, making the case that a superintelligent AI with misaligned goals could pose an existential risk to humanity — a claim that has moved from fringe to mainstream over the last decade.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'nick-bostrom';
UPDATE thinkers SET image_url = 'https://substack-post-media.s3.amazonaws.com/public/images/3c6a6231-021b-4b82-9c92-6f16691b6652_400x400.jpeg', bio = COALESCE(NULLIF(bio, ''), 'Packy McCormick is the founder of Not Boring, one of the most widely-read business and technology newsletters. A former banker turned writer, he is known for long-form deep dives into ambitious companies and ideas — and for consistently identifying the venture bets that define each technology cycle. His analysis of AI''s business model implications reaches hundreds of thousands of operators and investors.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'packy-mccormick';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Peter-Diamandis-Headshot.jpg/500px-Peter-Diamandis-Headshot.jpg', bio = COALESCE(NULLIF(bio, ''), 'Peter Diamandis is the founder of XPRIZE and Singularity University, and a prolific entrepreneur across longevity, space, and AI ventures. Author of ''Abundance'' and ''The Future is Faster than You Think'', he is the archetype of exponential optimism — arguing that converging technologies are on the verge of solving humanity''s greatest problems, and that scarcity itself is solvable.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'peter-diamandis';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8e/2022_Reid_Hoffman_%28cropped%29.jpg/500px-2022_Reid_Hoffman_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Reid Hoffman is the co-founder of LinkedIn, a partner at Greylock, and one of Silicon Valley''s most connected and widely-read thinkers on technology and entrepreneurship. An early backer of OpenAI and author of ''Impromptu: Amplifying Our Humanity Through AI'', he argues that AI''s potential to amplify human possibility at scale is civilisationally significant — and that optimism is a moral stance, not a naive one.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'reid-hoffman';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Robin_Hanson_in_a_field_2.jpg/500px-Robin_Hanson_in_a_field_2.jpg', bio = COALESCE(NULLIF(bio, ''), 'Robin Hanson is an associate professor of economics at George Mason University and a research associate at Oxford''s Future of Humanity Institute. Author of ''The Age of Em'', which imagines an economy dominated by brain emulations, and ''The Elephant in the Brain'', he brings contrarian economic analysis to questions of AI impact — often reaching conclusions that mainstream forecasters overlook.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'robin-hanson';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/SXSW-2024-OB7A0236-alih-Rohit_Bhargava.jpg/500px-SXSW-2024-OB7A0236-alih-Rohit_Bhargava.jpg', bio = COALESCE(NULLIF(bio, ''), 'Rohit Bhargava is a trend forecaster, marketing strategist, and author of the Non-Obvious Trend Report series. A former Ogilvy executive and Georgetown professor, he identifies under-reported cultural signals — the ''non-obvious'' patterns that conventional analysis misses — making him a useful counterpoint to technology-first views of where consumer behaviour is heading.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'rohit-bhargava';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f8/Sam_Altman_TechCrunch_SF_2019_Day_2_Oct_3_%28cropped_3%29.jpg/500px-Sam_Altman_TechCrunch_SF_2019_Day_2_Oct_3_%28cropped_3%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Sam Altman is the CEO of OpenAI, the company that launched ChatGPT to 100 million users in under two months — the fastest product adoption in history. A former YCombinator president and prolific investor in nuclear fusion, robotics, and AI infrastructure, he is arguably the most consequential operator in the current AI wave and one of its most public faces.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'sam-altman';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/MS-Exec-Nadella-Satya-2017-08-31-22_%28cropped%29.jpg/500px-MS-Exec-Nadella-Satya-2017-08-31-22_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Satya Nadella is the CEO of Microsoft, where he has led one of the most remarkable corporate reinventions in technology history — transforming the company from a declining desktop software giant into the world''s most AI-integrated enterprise platform. His $13 billion investment in OpenAI and integration of Copilot across Microsoft 365 have made him a defining figure in enterprise AI adoption.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'satya-nadella';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/62/TNW_USA_2014_%2816085105617%29_%28cropped%29.jpg/500px-TNW_USA_2014_%2816085105617%29_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Scott Belsky is the founder of Behance and Chief Product Officer at Adobe, giving him a unique vantage point on how AI is transforming creative work. Author of ''The Messy Middle'' and ''Imagining the Future'', he writes on how new technologies reshape the creative professions — and why the human skills of taste, judgement, and vision become more rather than less important as tools become more powerful.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'scott-belsky';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2b/Scott_Galloway_%2851933097365%29_%28cropped%29.jpg/500px-Scott_Galloway_%2851933097365%29_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Scott Galloway is a professor of marketing at NYU Stern School of Business, co-host of the Pivot podcast, and one of the most acerbic commentators on big tech. Author of ''The Four'', ''Post Corona'', and ''Adrift'', his analysis combines rigorous data with unsparing critique of platform monopolies, inequality, and the failure of institutions. A rare mainstream voice warning of AI''s distributional costs.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'scott-galloway';
UPDATE thinkers SET image_url = 'https://sineadbovell.com/assets/Sinead_Bio_Photo-C_xlCQyS.jpg', bio = COALESCE(NULLIF(bio, ''), 'Sinead Bovell is a futurist, technologist, and founder of WAYE — a media platform focused on educating young people about the future of technology. Known for making complex AI and futures thinking accessible and visual, she is a prominent voice on how AI intersects with identity, work, and the next generation''s economic prospects.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'sinead-bovell';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/95/Tristan_Harris_crop.jpg/500px-Tristan_Harris_crop.jpg', bio = COALESCE(NULLIF(bio, ''), 'Tristan Harris is the co-founder of the Center for Humane Technology and a former design ethicist at Google. His TED talk ''How a Handful of Tech Companies Control Billions of Minds'' made persuasive technology a mainstream policy concern. With AI, he is one of the most urgent voices warning that AI systems optimised for engagement can cause civilisational-scale harm if deployed without alignment to human wellbeing.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'tristan-harris';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8e/Laura_Chaubard_%26_Yann_Le_Cun_-_2024_%2853814052697%29_%28cropped%29.jpg/500px-Laura_Chaubard_%26_Yann_Le_Cun_-_2024_%2853814052697%29_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Yann LeCun is the Chief AI Scientist at Meta and a professor at NYU. A pioneer of convolutional neural networks and co-recipient of the 2018 Turing Award, he is the most prominent scientific sceptic of the idea that current large language model architectures can reach human-level general intelligence. His advocacy for alternative AI approaches — especially world models and video prediction — makes him a vital counterpoint to the GPT-centric consensus.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'yann-lecun';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/6/6d/Acemoglu_2016_%283x4_cropped%29.png', bio = COALESCE(NULLIF(bio, ''), 'Daron Acemoglu is an economist at MIT and co-winner of the 2024 Nobel Prize in Economics, awarded for his work on institutions and prosperity. His book ''Power and Progress'', co-authored with Simon Johnson, makes the most rigorous mainstream case that AI''s gains are being captured by a small elite rather than distributed broadly — and that this outcome is a choice, not an inevitability.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'daron-acemoglu';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6b/Re_publica_2015_-_Tag_1_%2817379378221%29.jpg/500px-Re_publica_2015_-_Tag_1_%2817379378221%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'James Bridle is a British writer, artist, and technologist whose work spans essays, installations, and books. Author of ''New Dark Age'' and ''Ways of Being'', they argue that computation has made the world less legible, not more — and that truly intelligent systems already exist in nature in ways that challenge the anthropocentric assumptions behind AI development.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'james-bridle';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Matt_Britton.jpg/500px-Matt_Britton.jpg', bio = COALESCE(NULLIF(bio, ''), 'Matt Britton is the founder and CEO of Suzy, a consumer intelligence platform, and host of the Speed of Culture podcast. A longtime strategist on youth and cultural trends, he tracks how AI is transforming consumer behaviour, brand strategy, and the creative industries — translating technological shifts into actionable frameworks for marketers and executives.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'matt-britton';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/Tyler_Cowen_1.jpg/500px-Tyler_Cowen_1.jpg', bio = COALESCE(NULLIF(bio, ''), 'Tyler Cowen is an economist at George Mason University, co-author of the Marginal Revolution blog, and host of Conversations with Tyler. Author of ''Average Is Over'' and ''Talent'', he is one of the most widely-read economists on AI''s long-run economic implications — consistently arguing that AI will stratify society sharply between those who can complement it and those who cannot.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'tyler-cowen';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/Rana_El_Kaliouby.jpg/500px-Rana_El_Kaliouby.jpg', bio = COALESCE(NULLIF(bio, ''), 'Rana el Kaliouby is a pioneering AI scientist and entrepreneur, founder of Affectiva — the first company to commercialise emotion AI — and author of ''Girl Decoded''. An Egyptian-American MIT-trained researcher, she has spent two decades building technology that reads human emotion from facial expressions, placing her at the centre of debates about AI and emotional intelligence, privacy, and bias.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'rana-el-kaliouby';
UPDATE thinkers SET image_url = 'https://images.squarespace-cdn.com/content/v1/50363cf324ac8e905e7df861/7697741e-0a89-4bb3-b69c-a9e62753e1f9/BEvans_BenedictEvans_170_Final%2Bsmall.jpg?format=500w', bio = COALESCE(NULLIF(bio, ''), 'Benedict Evans is an independent technology analyst and former partner at Andreessen Horowitz. His widely-read newsletter and annual presentations are benchmarks for rigorous thinking on how major technology platforms evolve — and his analysis of AI''s structural effects on software, media, and enterprise has shaped how operators and investors frame the current transition.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'benedict-evans';
UPDATE thinkers SET image_url = 'https://eandtbooks.com/wp-content/uploads/2020/11/Tracey-Follows-lo-res-scaled.jpg', bio = COALESCE(NULLIF(bio, ''), 'Tracey Follows is a futurist, author, and founder of Futuremade, a strategic foresight consultancy. Author of ''The Future of You: Can Your Identity Survive 21st-Century Technology?'', she focuses on digital identity, personal data, and how AI is reshaping what it means to be an individual — bringing a rare consumer-anthropology perspective to futures thinking dominated by engineers and economists.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'tracey-follows';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0d/Martin_Ford_Speaking_July_2016.jpg/500px-Martin_Ford_Speaking_July_2016.jpg', bio = COALESCE(NULLIF(bio, ''), 'Martin Ford is a futurist and author of ''Rise of the Robots'' and ''Rule of the Robots'', two of the most widely-read popular accounts of AI-driven labour displacement. A Silicon Valley entrepreneur who predicted the automation wave before it became mainstream debate, he consistently argues that the breadth and speed of AI''s impact on employment exceeds what most economists are willing to acknowledge.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'martin-ford';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/e/e3/Paulgraham_240x320.jpg', bio = COALESCE(NULLIF(bio, ''), 'Paul Graham is the co-founder of Y Combinator, the world''s most influential startup accelerator, and one of the most-read essayists on technology and entrepreneurship. His essays on startups, founders, and the nature of ideas have shaped a generation of builders; his recent writing on AI addresses how it changes what startups can do and what kinds of founders will thrive.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'paul-graham';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/65/Bill_Gurley%2C_2013.jpg/500px-Bill_Gurley%2C_2013.jpg', bio = COALESCE(NULLIF(bio, ''), 'Bill Gurley is a general partner at Benchmark Capital and one of Silicon Valley''s most respected venture capitalists, known for early bets on Uber, Zillow, and OpenTable. His analytical writing on market structure, platform economics, and capital allocation has shaped how practitioners think about technology cycles — and his scepticism of AI valuations and hype cycles provides a grounding counterpoint to frontier optimism.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'bill-gurley';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/58/MKr364751_Yuval_Noah_Harari_%28Frankfurter_Buchmesse_2024%29.jpg/500px-MKr364751_Yuval_Noah_Harari_%28Frankfurter_Buchmesse_2024%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Yuval Noah Harari is a historian at the Hebrew University of Jerusalem and author of ''Sapiens'', ''Homo Deus'', and ''21 Lessons for the 21st Century'' — books that collectively sold tens of millions of copies. His 2024 book ''Nexus'' examines AI through the lens of information networks across history, arguing that AI is the first technology capable of making autonomous decisions and that this makes it categorically different from all prior tools.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'yuval-noah-harari';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ac/ASSA_2025_-_Chad_Jones_01.jpg/500px-ASSA_2025_-_Chad_Jones_01.jpg', bio = COALESCE(NULLIF(bio, ''), 'Charles I. Jones (known as Chad Jones) is an economist at Stanford''s Graduate School of Business specialising in long-run economic growth. His models of ideas-driven growth have been foundational in macroeconomics; his recent research on AI and growth — including work on ''AI and Economic Growth'' — provides some of the most technically rigorous academic frameworks for projecting how AI-driven automation could reshape the entire growth trajectory of the global economy.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'charles-i-jones';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f7/2024-03-14_SXSW_Vinod-Khosla_08741.jpg/500px-2024-03-14_SXSW_Vinod-Khosla_08741.jpg', bio = COALESCE(NULLIF(bio, ''), 'Vinod Khosla is the founder of Khosla Ventures and a co-founder of Sun Microsystems, one of Silicon Valley''s most consequential early investors and technologists. An aggressive AI maximalist, he has publicly predicted that AI will replace 80% of jobs, render most doctors obsolete, and that this is net-positive — making him one of the most quoted and most contested voices in debates about AI and labour.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'vinod-khosla';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/96/Ray_Kurzweil_%40_SXSW_2017_%2832594766664%29.jpg/500px-Ray_Kurzweil_%40_SXSW_2017_%2832594766664%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Ray Kurzweil is an inventor, futurist, and director of engineering at Google, best known for his concept of the Singularity — the moment when AI exceeds human intelligence and accelerates beyond prediction. His 1999 prediction that a computer would beat a chess champion came true, and his 2005 book ''The Singularity Is Near'' has shaped a generation of AI optimists; his 2024 follow-up ''The Singularity Is Nearer'' doubles down on a 2029 AGI target.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'ray-kurzweil';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/2007GoogleTaiwanPressConference_KaifuLee.jpg/500px-2007GoogleTaiwanPressConference_KaifuLee.jpg', bio = COALESCE(NULLIF(bio, ''), 'Kai-Fu Lee is the founder of Sinovation Ventures and one of the foremost authorities on AI in China. A former president of Google China, he wrote ''AI Superpowers'', the defining account of the US-China AI race — arguing that China''s data advantages and implementation speed make it a genuine peer competitor, not a follower. His 2023 novel ''AI 2041'' co-authored with Chen Qiufan explored AI''s social implications through fiction.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'kai-fu-lee';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/71/Annie_Lowrey_%2829603514326%29.jpg/500px-Annie_Lowrey_%2829603514326%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Annie Lowrey is a staff writer at The Atlantic covering economic policy, inequality, and the politics of poverty. Author of ''Give People Money'', a landmark argument for universal basic income, her reporting on AI focuses on its distributional effects — who captures the gains, who bears the displacement costs, and whether existing policy frameworks are remotely adequate to manage the transition.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'annie-lowrey';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/77/Dwarkesh-Panel-2026.jpg/500px-Dwarkesh-Panel-2026.jpg', bio = COALESCE(NULLIF(bio, ''), 'Dwarkesh Patel is the host of the Dwarkesh Podcast, which has become one of the most technically substantive long-form interview series on AI — featuring extended conversations with leading researchers at Anthropic, DeepMind, and OpenAI. His willingness to engage with deep technical and philosophical questions has made him a primary venue for frontier AI thinkers to develop and stress-test their ideas publicly.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'dwarkesh-patel';
UPDATE thinkers SET image_url = 'https://substack-post-media.s3.amazonaws.com/public/images/09a0884f-470c-4b99-b674-41f20b350acc_1837x1837.png', bio = COALESCE(NULLIF(bio, ''), 'Scott Santens is a writer and UBI advocate who has spent over a decade making the evidence-based case for universal basic income as a response to automation. A leading voice in the basic income research community, his work synthesises economic evidence, policy design, and political strategy — and he has become increasingly focused on AI as the accelerant that makes robust income floors an urgent policy priority rather than a distant aspiration.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'scott-santens';
UPDATE thinkers SET image_url = 'https://consilienceproject.org/wp-content/uploads/2022/11/Daniel-Schmachtenberger_Head-Shot-Cropped-300x300.jpg', bio = COALESCE(NULLIF(bio, ''), 'Daniel Schmachtenberger is a founding member of the Consilience Project and one of the most systematic thinkers on civilisational risk and AI governance. His framework of ''generator functions'' — the deep structural drivers producing existential risk — has influenced a generation of AI safety and longtermism researchers. He argues that narrow AI safety misses the deeper problem: that the social and economic systems deploying AI are themselves misaligned with human flourishing.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'daniel-schmachtenberger';
UPDATE thinkers SET image_url = 'https://substack-post-media.s3.amazonaws.com/public/images/58e4731b-0451-4d5e-b90d-0b991bbba2fc_441x441.jpeg', bio = COALESCE(NULLIF(bio, ''), 'Noah Smith is an economist, Bloomberg Opinion columnist, and author of the Noahpinion Substack, one of the most widely-read economics publications online. A former finance professor at Stony Brook University, he writes with unusual range — covering AI''s macroeconomic implications, labour market dynamics, and technology policy with a rigorous but accessible style that reaches both specialist and general audiences.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'noah-smith';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Balaji_Srinivasan_%28cropped%29.png/500px-Balaji_Srinivasan_%28cropped%29.png', bio = COALESCE(NULLIF(bio, ''), 'Balaji Srinivasan is a serial entrepreneur, former CTO of Coinbase, and author of ''The Network State'', which argues that crypto-enabled communities will replace nation-states as the primary form of political organisation. One of Silicon Valley''s most provocative macro thinkers, he combines AI, crypto, and geopolitics into a distinctive accelerationist worldview — and his predictions, however extreme, consistently frame debates that mainstream analysts catch up with later.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'balaji-srinivasan';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c1/ECommerce_Week_of_UNCTAD_%2841520003051%29_%28cropped%29.jpg/500px-ECommerce_Week_of_UNCTAD_%2841520003051%29_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Nick Srnicek is a political economist at King''s College London and co-author of ''Inventing the Future'' and author of ''Platform Capitalism''. His analysis of how digital platforms concentrate market power, extract rent, and reshape labour has become essential reading for anyone understanding the economic structure AI is being built on top of — and why left political economy can''t ignore it.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'nick-srnicek';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/Future_Affairs_Berlin_2019_-_%E2%80%9EDigital_Revolution_Resetting_Global_Power_Politics%3F%E2%80%9C_%2847959578672%29.jpg/500px-Future_Affairs_Berlin_2019_-_%E2%80%9EDigital_Revolution_Resetting_Global_Power_Politics%3F%E2%80%9C_%2847959578672%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Hito Steyerl is a German filmmaker, visual artist, and writer whose essays and installations interrogate how images, data, and AI systems mediate power and reality. Her essay collections ''The Wretched of the Screen'' and ''Duty Free Art'' are canonical texts in contemporary media theory. She approaches AI not through technical or economic lenses but through questions of aesthetics, violence, and whose worlds get represented in training data.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'hito-steyerl';
UPDATE thinkers SET image_url = 'https://fastfuture.com/wp-content/uploads/Rohit-Talwar-1-340x400.jpg', bio = COALESCE(NULLIF(bio, ''), 'Rohit Talwar is the CEO of Fast Future, a foresight and futures research firm, and a prolific author of scenario-based futures publications. Specialising in structured futures methodology, he helps governments, corporations, and institutions map plausible AI scenarios across 10-20 year horizons — occupying a practitioner niche between academic foresight and strategic consulting.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'rohit-talwar';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/Max_Tegmark_2024_%28cropped%29.jpg/500px-Max_Tegmark_2024_%28cropped%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Max Tegmark is a physicist at MIT and co-founder of the Future of Life Institute, one of the most influential organisations in AI safety. Author of ''Life 3.0: Being Human in the Age of Artificial Intelligence'', he brings a cosmological perspective to AI risk — arguing that the decisions made in the next decade about AI alignment will shape the entire future of life in the universe, not just human civilisation.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'max-tegmark';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/4/4c/Amy_Webb_2018.jpg', bio = COALESCE(NULLIF(bio, ''), 'Amy Webb is the founder of the Future Today Institute and a professor at NYU Stern School of Business, producing one of the most rigorous annual technology trend reports in the industry. Her book ''The Big Nine'' documented the concentrated power of the companies building AI before it was mainstream concern; her Emerging Tech Trend Report has become a reference document in corporate strategy and policy circles.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'amy-webb';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/be/KevinWerbachJI2.jpg/500px-KevinWerbachJI2.jpg', bio = COALESCE(NULLIF(bio, ''), 'Kevin Werbach is a professor of legal studies and business ethics at the Wharton School and a former FCC official. Author of ''The Blockchain and the New Architecture of Trust'', his research on AI governance, platform regulation, and the intersection of technology and law makes him a rigorous voice in policy debates that often lack technical grounding. His Accountable AI initiative focuses on practical regulatory frameworks for deployed AI systems.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'kevin-werbach';
UPDATE thinkers SET image_url = 'https://storage.theconversation.com/76qzf0gu52s963grxdk5iraqfsxi', bio = COALESCE(NULLIF(bio, ''), 'Alex Williams is a political theorist and co-author, with Nick Srnicek, of ''Inventing the Future: Postcapitalism and a World Without Work'' — a manifesto arguing that the left must embrace automation, reclaim technology from capital, and build towards a post-work society. His theoretical work provides the political-philosophical grounding for debates about AI, labour, and what radical futures might look like beyond the wage relation.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'alex-williams';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/TNW_Latin_America_2012_-_Day_1_%287995878666%29.jpg/500px-TNW_Latin_America_2012_-_Day_1_%287995878666%29.jpg', bio = COALESCE(NULLIF(bio, ''), 'Michell Zappa is the founder of Envisioning, a strategic foresight studio known for producing some of the most visually rigorous technology roadmaps and futures scenarios. His work translates complex technology trajectories — including AI, robotics, and biotech — into structured visual frameworks used by governments, corporations, and research institutions to plan across 5-30 year horizons.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'michell-zappa';
UPDATE thinkers SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/Shoshana_Zuboff_at_Alexander_von_Humboldt_Institut.jpg/500px-Shoshana_Zuboff_at_Alexander_von_Humboldt_Institut.jpg', bio = COALESCE(NULLIF(bio, ''), 'Shoshana Zuboff is an emerita professor at Harvard Business School and author of ''The Age of Surveillance Capitalism'', one of the most influential books on technology published in the last decade. Her concept of ''surveillance capitalism'' — the commodification of human behavioural data as raw material for prediction products — has become the dominant critical framework for understanding how AI systems are funded, trained, and deployed.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'shoshana-zuboff';
UPDATE thinkers SET image_url = 'https://images.squarespace-cdn.com/content/v1/5ddb7f1f3ad7035a26308940/c9b78d97-8de2-4844-bb7a-49d301a64051/Roger+S+-+JCo+Studios+-9982.jpg', bio = COALESCE(NULLIF(bio, ''), 'Roger Spitz is a futurist, author, and founder of Techistential, focused on applied futures thinking for boards, executives, and investors. Author of ''The Definitive Guide to Thriving on Disruption'', he specialises in helping organisations build futures literacy — the capacity to think rigorously about uncertainty rather than projecting present trends linearly into a destabilising future.') WHERE trim(both '-' from regexp_replace(lower(name), '[^a-z0-9]+', '-', 'g')) = 'roger-spitz';

